-- Create "business_record_events" table
CREATE TABLE "business_record_events" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "record_id" bigint NULL,
  "module_key" character varying NOT NULL,
  "action_key" character varying NOT NULL,
  "from_status_key" character varying NULL,
  "to_status_key" character varying NULL,
  "actor_id" bigint NULL,
  "actor_role_key" character varying NULL,
  "note" character varying NULL,
  "payload" jsonb NULL,
  "created_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "businessrecordevent_created_at" to table: "business_record_events"
CREATE INDEX "businessrecordevent_created_at" ON "business_record_events" ("created_at");
-- Create index "businessrecordevent_module_key_action_key" to table: "business_record_events"
CREATE INDEX "businessrecordevent_module_key_action_key" ON "business_record_events" ("module_key", "action_key");
-- Create index "businessrecordevent_record_id" to table: "business_record_events"
CREATE INDEX "businessrecordevent_record_id" ON "business_record_events" ("record_id");
-- Create "business_record_items" table
CREATE TABLE "business_record_items" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "record_id" bigint NOT NULL,
  "module_key" character varying NOT NULL,
  "line_no" bigint NOT NULL DEFAULT 1,
  "item_name" character varying NULL,
  "material_name" character varying NULL,
  "spec" character varying NULL,
  "unit" character varying NULL,
  "quantity" double precision NULL,
  "unit_price" double precision NULL,
  "amount" double precision NULL,
  "supplier_name" character varying NULL,
  "warehouse_location" character varying NULL,
  "payload" jsonb NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "businessrecorditem_module_key" to table: "business_record_items"
CREATE INDEX "businessrecorditem_module_key" ON "business_record_items" ("module_key");
-- Create index "businessrecorditem_record_id" to table: "business_record_items"
CREATE INDEX "businessrecorditem_record_id" ON "business_record_items" ("record_id");
-- Create index "businessrecorditem_record_id_line_no" to table: "business_record_items"
CREATE INDEX "businessrecorditem_record_id_line_no" ON "business_record_items" ("record_id", "line_no");
-- Create "business_records" table
CREATE TABLE "business_records" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "module_key" character varying NOT NULL,
  "document_no" character varying NULL,
  "title" character varying NOT NULL,
  "business_status_key" character varying NOT NULL,
  "owner_role_key" character varying NOT NULL,
  "source_no" character varying NULL,
  "customer_name" character varying NULL,
  "supplier_name" character varying NULL,
  "style_no" character varying NULL,
  "product_no" character varying NULL,
  "product_name" character varying NULL,
  "material_name" character varying NULL,
  "warehouse_location" character varying NULL,
  "quantity" double precision NULL,
  "unit" character varying NULL,
  "amount" double precision NULL,
  "document_date" character varying NULL,
  "due_date" character varying NULL,
  "payload" jsonb NULL,
  "row_version" bigint NOT NULL DEFAULT 1,
  "created_by" bigint NULL,
  "updated_by" bigint NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  "deleted_by" bigint NULL,
  "delete_reason" character varying NULL,
  PRIMARY KEY ("id")
);
-- Create index "businessrecord_module_key" to table: "business_records"
CREATE INDEX "businessrecord_module_key" ON "business_records" ("module_key");
-- Create index "businessrecord_module_key_business_status_key" to table: "business_records"
CREATE INDEX "businessrecord_module_key_business_status_key" ON "business_records" ("module_key", "business_status_key");
-- Create index "businessrecord_module_key_deleted_at" to table: "business_records"
CREATE INDEX "businessrecord_module_key_deleted_at" ON "business_records" ("module_key", "deleted_at");
-- Create index "businessrecord_module_key_document_no" to table: "business_records"
CREATE UNIQUE INDEX "businessrecord_module_key_document_no" ON "business_records" ("module_key", "document_no") WHERE ((deleted_at IS NULL) AND (document_no IS NOT NULL) AND ((document_no)::text <> ''::text));
-- Create index "businessrecord_module_key_owner_role_key" to table: "business_records"
CREATE INDEX "businessrecord_module_key_owner_role_key" ON "business_records" ("module_key", "owner_role_key");
